const e={boardTopology:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Découvrez comment les cartes de contrôle de votre imprimante se connectent : l'hôte (SBC) et chaque MCU avec lequel il communique, avec chaque type de connexion et une estimation au mieux de la carte / puce — lue en direct depuis la configuration."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Aide"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"À propos de la topologie des cartes"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Fermer"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Comment lire"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"L'hôte (votre SBC, par ex. un Raspberry Pi ou un CB1) se trouve en haut."}},{t:0,b:{t:2,i:[{t:3}],s:"Chaque carte MCU indique comment elle se connecte (USB / CAN bus / UART) et sa puce."}},{t:0,b:{t:2,i:[{t:3}],s:"Une estimation de la carte apparaît lorsque l'identifiant de connexion correspond à une carte connue."}}],topics:{mcus:{title:{t:0,b:{t:2,i:[{t:3}],s:"MCU"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Un MCU est une carte à microcontrôleur qui pilote les moteurs, les chauffages et les capteurs. Une imprimante en possède au moins un (la carte mère) ; beaucoup ajoutent une carte de tête d'impression et parfois une carte de palpeur ou de LED. Ce panneau liste chaque section `[mcu]` connue de Klipper."}}},connections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Types de connexion"}},body:{t:0,b:{t:2,i:[{t:3}],s:"USB — une liaison série sur USB (la connexion habituelle de la carte mère). CAN bus — un bus partagé à deux fils, courant pour les cartes de tête d'impression. UART — une liaison série directe via GPIO. Le type est déduit du paramètre `serial` / `canbus_uuid` de chaque MCU."}}},detection:{title:{t:0,b:{t:2,i:[{t:3}],s:"Comment fonctionne la détection"}},body:{t:0,b:{t:2,i:[{t:3}],s:"La puce et la carte sont estimées en comparant l'identifiant de connexion (le chemin série ou l'UUID CAN) à une table de motifs. Une estimation de carte affiche un indice de confiance ; lorsque rien ne correspond, la puce/carte indique « inconnu » — la connexion elle-même reste affichée."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossaire"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{mcu:{term:{t:0,b:{t:2,i:[{t:3}],s:"MCU"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Microcontroller unit — une carte de contrôle exécutant le firmware de Klipper (carte mère, tête d'impression, etc.)."}}},canbus:{term:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un bus partagé à deux fils reliant les cartes par un UUID unique — populaire pour le câblage des têtes d'impression."}}},host:{term:{t:0,b:{t:2,i:[{t:3}],s:"Hôte / SBC"}},def:{t:0,b:{t:2,i:[{t:3}],s:"L'ordinateur monocarte (Pi, CB1, …) qui exécute Klipper et communique avec les MCU."}}}}},host:{label:{t:0,b:{t:2,i:[{t:3}],s:"Hôte"}},role:{t:0,b:{t:2,i:[{t:3}],s:"Ordinateur monocarte — exécute Klipper"}}},mcu:{chip:{t:0,b:{t:2,i:[{t:3}],s:"Puce"}},board:{t:0,b:{t:2,i:[{t:3}],s:"Carte"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"inconnu"}},identifier:{t:0,b:{t:2,i:[{t:3}],s:"Identifiant"}},confidence:{t:0,b:{t:2,i:[{t:4,k:"pct"},{t:3,v:" % de correspondance"}]}}},conn:{canbus:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},usb:{t:0,b:{t:2,i:[{t:3}],s:"USB"}},uart:{t:0,b:{t:2,i:[{t:3}],s:"UART"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"inconnu"}},via:{t:0,b:{t:2,i:[{t:3,v:"via "},{t:4,k:"type"}]}}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" MCU"}]}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Lecture de la topologie…"}},unreachable:{t:0,b:{t:2,i:[{t:3}],s:"Impossible de joindre l'imprimante."}},empty:{t:0,b:{t:2,i:[{t:3}],s:"Aucun MCU trouvé dans la configuration."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Réessayer"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Actualiser"}}}}};export{e as default};
